### Pinia vs Vuex

Pinia is the official state management library for Vue 3, replacing Vuex:

| Feature | Pinia | Vuex |
|---|---|---|
| API Design | Composition-first | Options-first |
| TypeScript | Full support | Manual setup |
| Mutations | Not needed (direct mutation) | Required |
| Devtools | Full support | Full support |
| Bundle size | ~1 KB | ~9 KB |

### defineStore

```js
import { defineStore } from 'pinia'

export const useCounterStore = defineStore('counter', {
  state: () => ({ count: 0 }),
  getters: {
    double: (state) => state.count * 2
  },
  actions: {
    increment() {
      this.count++
    }
  }
})
```

### Using a Store

```vue
<script>
import { useCounterStore } from '@/stores/counter'
export default {
  setup() {
    const store = useCounterStore()
    return { store }
  }
}
</script>

<template>
  <p>{{ store.count }}</p>
  <p>Double: {{ store.double }}</p>
  <button @click="store.increment()">Add</button>
</template>
```

### Setup Stores vs Options Stores

**Options store** (declarative):

```js
export const useStore = defineStore('id', {
  state: () => ({ ... }),
  getters: { ... },
  actions: { ... }
})
```

**Setup store** (composition-style):

```js
export const useStore = defineStore('id', () => {
  const count = ref(0)
  const double = computed(() => count.value * 2)
  function increment() { count.value++ }
  return { count, double, increment }
})
```

### Installing Pinia

```js
import { createPinia } from 'pinia'

const app = createApp(App)
app.use(createPinia())
app.mount('#app')
```

codeExample:
// stores/user.js
import { defineStore } from 'pinia'

export const useUserStore = defineStore('user', () => {
  const name = ref('')
  const isLoggedIn = computed(() => name.value !== '')

  function login(username) {
    name.value = username
  }
  function logout() {
    name.value = ''
  }

  return { name, isLoggedIn, login, logout }
})

